#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <limits.h>

#define MAX_REFERENCE 100
#define MAX_FRAMES 10

// Structure to hold algorithm results
typedef struct {
 int page_faults;
 int page_hits;
} Result;

// Check if page is already in frames
bool isInFrames(int frames[], int num_frames, int page) {
 for (int i = 0; i < num_frames; i++) {
 if (frames[i] == page) {
 return true;
 }
 }
 return false;
}

// Find the position of page in frames
int findPagePosition(int frames[], int num_frames, int page) {
 for (int i = 0; i < num_frames; i++) {
 if (frames[i] == page) {
 return i;
 }
 }
 return -1;
}

// FIFO Page Replacement Algorithm
Result fifo_algorithm(int reference[], int ref_length, int num_frames) {
 int frames[MAX_FRAMES];
 int queue[MAX_FRAMES]; // To track arrival order
 int front = 0, rear = 0;
 Result result = {0, 0};

 // Initialize frames to -1 (empty)
 for (int i = 0; i < num_frames; i++) {
 frames[i] = -1;
 queue[i] = -1;
 }

 printf("\n=== FIFO Algorithm ===\n");

 int frame_count = 0;

 for (int i = 0; i < ref_length; i++) {
 int page = reference[i];
 printf("Reference: %d -> ", page);

 if (!isInFrames(frames, num_frames, page)) {
 // Page fault
 result.page_faults++;
 printf("FAULT ");

 if (frame_count < num_frames) {
 // Use empty frame
 frames[frame_count] = page;
 queue[rear++] = page;
 frame_count++;
 } else {
 // Replace oldest page (FIFO)
 int victim = queue[front++];
 int pos = findPagePosition(frames, num_frames, victim);
 frames[pos] = page;
 queue[rear++] = page;
 }
 } else {
 // Page hit
 result.page_hits++;
 printf("HIT ");
 }

 // Print current frames
 printf("Frames: [");
 for (int j = 0; j < num_frames; j++) {
 if (frames[j] != -1) {
 printf("%d", frames[j]);
 } else {
 printf("-");
 }
 if (j < num_frames - 1) printf(" ");
 }
 printf("]\n");
 }

 printf("Total Page Faults: %d\n", result.page_faults);
 return result;
}

// Find next use of a page in the reference string
int findNextUse(int reference[], int ref_length, int start, int page) {
 for (int i = start; i < ref_length; i++) {
 if (reference[i] == page) {
 return i;
 }
 }
 return INT_MAX; // Not used again
}

// Optimal (OPT) Page Replacement Algorithm
Result optimal_algorithm(int reference[], int ref_length, int num_frames) {
 int frames[MAX_FRAMES];
 Result result = {0, 0};

 // Initialize frames
 for (int i = 0; i < num_frames; i++) {
 frames[i] = -1;
 }

 printf("\n=== Optimal (OPT) Algorithm ===\n");

 int frame_count = 0;

 for (int i = 0; i < ref_length; i++) {
 int page = reference[i];
 printf("Reference: %d -> ", page);

 if (!isInFrames(frames, num_frames, page)) {
 result.page_faults++;
 printf("FAULT ");

 if (frame_count < num_frames) {
 frames[frame_count++] = page;
 } else {
 // Find page with farthest next use
 int victim_idx = -1;
 int max_future = -1;

 for (int j = 0; j < num_frames; j++) {
 int next_use = findNextUse(reference, ref_length, i + 1, frames[j]);
 if (next_use > max_future) {
 max_future = next_use;
 victim_idx = j;
 }
 }

 frames[victim_idx] = page;
 }
 } else {
 result.page_hits++;
 printf("HIT ");
 }

 // Print current frames
 printf("Frames: [");
 for (int j = 0; j < num_frames; j++) {
 if (frames[j] != -1) {
 printf("%d", frames[j]);
 } else {
 printf("-");
 }
 if (j < num_frames - 1) printf(" ");
 }
 printf("]\n");
 }

 printf("Total Page Faults: %d\n", result.page_faults);
 return result;
}

// LRU Page Replacement Algorithm
Result lru_algorithm(int reference[], int ref_length, int num_frames) {
 int frames[MAX_FRAMES];
 int last_used[MAX_FRAMES]; // Track last use time for each frame
 Result result = {0, 0};
 int current_time = 0;

 // Initialize frames
 for (int i = 0; i < num_frames; i++) {
 frames[i] = -1;
 last_used[i] = -1;
 }

 printf("\n=== LRU Algorithm ===\n");

 int frame_count = 0;

 for (int i = 0; i < ref_length; i++) {
 int page = reference[i];
 printf("Reference: %d -> ", page);

 if (!isInFrames(frames, num_frames, page)) {
 result.page_faults++;
 printf("FAULT ");

 if (frame_count < num_frames) {
 frames[frame_count] = page;
 last_used[frame_count] = current_time;
 frame_count++;
 } else {
 // Find LRU page (smallest last_used value)
 int lru_idx = 0;
 int min_time = last_used[0];

 for (int j = 1; j < num_frames; j++) {
 if (last_used[j] < min_time) {
 min_time = last_used[j];
 lru_idx = j;
 }
 }

 frames[lru_idx] = page;
 last_used[lru_idx] = current_time;
 }
 } else {
 result.page_hits++;
 printf("HIT ");
 // Update last used time for the accessed page
 int pos = findPagePosition(frames, num_frames, page);
 last_used[pos] = current_time;
 }

 current_time++;

 // Print current frames
 printf("Frames: [");
 for (int j = 0; j < num_frames; j++) {
 if (frames[j] != -1) {
 printf("%d", frames[j]);
 } else {
 printf("-");
 }
 if (j < num_frames - 1) printf(" ");
 }
 printf("]\n");
 }

 printf("Total Page Faults: %d\n", result.page_faults);
 return result;
}

// Main function
int main() {
 // Reference string from textbook
 int reference[] = {7, 0, 1, 2, 0, 3, 0, 4, 2, 3, 0, 3, 2, 1, 2, 0, 1, 7, 0, 1};
 int ref_length = sizeof(reference) / sizeof(reference[0]);
 int num_frames = 3;

 printf("===========================================");
 printf("\n PAGE REPLACEMENT ALGORITHMS COMPARISON");
 printf("\n===========================================\n");
 printf("Reference String: ");
 for (int i = 0; i < ref_length; i++) {
 printf("%d ", reference[i]);
 }
 printf("\nNumber of Frames: %d\n", num_frames);

 Result fifo_result, opt_result, lru_result;

 fifo_result = fifo_algorithm(reference, ref_length, num_frames);
 opt_result = optimal_algorithm(reference, ref_length, num_frames);
 lru_result = lru_algorithm(reference, ref_length, num_frames);

 // Summary
 printf("\n===========================================\n");
 printf(" SUMMARY\n");
 printf("===========================================\n");
 printf("| Algorithm | Page Faults | Page Hits |\n");
 printf("------------------------------------------- \n");
 printf("| FIFO | %d | %d |\n", 
 fifo_result.page_faults, fifo_result.page_hits);
 printf("| OPT | %d | %d |\n", 
 opt_result.page_faults, opt_result.page_hits);
 printf("| LRU | %d | %d |\n", 
 lru_result.page_faults, lru_result.page_hits);
 printf("===========================================\n");

 return 0;
}
